css:
.loader {
  position: relative;
  width: 8em;
  height: 8em;
  display: flex;
  align-items: center;
  justify-content: center;
}

.loader::before,
.loader::after {
position: absolute;
box-sizing: border-box;
content: "";
height: 8em;
width: 8em;
border: 1em solid #0060fa;
border-radius: 50%;
animation: loader_79178 2s linear infinite;
}

.loader::after {
opacity: 0;
animation-delay: 1s;
}

@keyframes loader_79178 {
0% {
border: 1em solid #0060fa;
transform: scale(0);
opacity: 1;
}

100% {
border: 0 solid #0060fa;
transform: scale(1);
opacity: 0;
}
}
